func bubbleSort(arr []int) {
	n := len(arr)
	for i := 0; i &lt; n-1; i++ {
		for j := 0; j &lt; n-i-1; j++ {
			if arr[j] &gt; arr[j+1] {
				arr[j], arr[j+1] = arr[j+1], arr[j]
			}
		}
	}
}

func selectionSort(arr []int) {
	n := len(arr)
	for i := 0; i &lt; n-1; i++ {
		minIdx := i
		for j := i + 1; j &lt; n; j++ {
			if arr[j] &lt; arr[minIdx] {
				minIdx = j
			}
		}
		arr[i], arr[minIdx] = arr[minIdx], arr[i]
	}
}

function insertionSort(arr: number[]): number[] {
  for (let i = 1; i &lt; arr.length; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j &gt;= 0 &amp;&amp; arr[j] &gt; key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
  return arr;
}

func quickSort(arr []int, low, high int) {
	if low &lt; high {
		pivot := partition(arr, low, high)
		quickSort(arr, low, pivot-1)
		quickSort(arr, pivot+1, high)
	}
}

func partition(arr []int, low, high int) int {
	pivot := arr[high]
	i := low - 1
	for j := low; j &lt; high; j++ {
		if arr[j] &lt;= pivot {
			i++
			arr[i], arr[j] = arr[j], arr[i]
		}
	}
	arr[i+1], arr[high] = arr[high], arr[i+1]
	return i + 1
}

func mergeSort(arr []int) []int {
	if len(arr) &lt;= 1 {
		return arr
	}
	mid := len(arr) / 2
	left := mergeSort(arr[:mid])
	right := mergeSort(arr[mid:])
	return merge(left, right)
}

func merge(l, r []int) []int {
	result := []int{}
	for len(l) &gt; 0 &amp;&amp; len(r) &gt; 0 {
		if l[0] &lt;= r[0] {
			result = append(result, l[0])
			l = l[1:]
		} else {
			result = append(result, r[0])
			r = r[1:]
		}
	}
	return append(result, append(l, r...)...)
}

public static void HeapSort(int[] arr) {
    int n = arr.Length;
    for (int i = n / 2 - 1; i &gt;= 0; i--)
        Heapify(arr, n, i);
    for (int i = n - 1; i &gt; 0; i--) {
        (arr[0], arr[i]) = (arr[i], arr[0]);
        Heapify(arr, i, 0);
    }
}

static void Heapify(int[] arr, int n, int i) {
    int largest = i, l = 2*i+1, r = 2*i+2;
    if (l &lt; n &amp;&amp; arr[l] &gt; arr[largest]) largest = l;
    if (r &lt; n &amp;&amp; arr[r] &gt; arr[largest]) largest = r;
    if (largest != i) {
        (arr[i], arr[largest]) = (arr[largest], arr[i]);
        Heapify(arr, n, largest);
    }
}

func countingSort(arr []int, maxVal int) []int {
	count := make([]int, maxVal+1)
	for _, v := range arr {
		count[v]++
	}
	result := []int{}
	for i, c := range count {
		for c &gt; 0 {
			result = append(result, i)
			c--
		}
	}
	return result
}

public static void RadixSort(int[] arr) {
    int max = arr.Max();
    for (int exp = 1; max / exp &gt; 0; exp *= 10)
        CountByDigit(arr, exp);
}

static void CountByDigit(int[] arr, int exp) {
    int n = arr.Length;
    int[] output = new int[n];
    int[] count = new int[10];
    foreach (var v in arr) count[(v / exp) % 10]++;
    for (int i = 1; i &lt; 10; i++) count[i] += count[i - 1];
    for (int i = n - 1; i &gt;= 0; i--) {
        int digit = (arr[i] / exp) % 10;
        output[--count[digit]] = arr[i];
    }
    Array.Copy(output, arr, n);
}

func linearSearch(arr []int, target int) int {
	for i, v := range arr {
		if v == target {
			return i
		}
	}
	return -1
}

func binarySearch(arr []int, target int) int {
	left, right := 0, len(arr)-1
	for left &lt;= right {
		mid := left + (right-left)/2
		if arr[mid] == target {
			return mid
		} else if arr[mid] &lt; target {
			left = mid + 1
		} else {
			right = mid - 1
		}
	}
	return -1
}

function jumpSearch(arr: number[], target: number): number {
  const n = arr.length;
  const step = Math.floor(Math.sqrt(n));
  let prev = 0, curr = step;
  while (curr &lt; n &amp;&amp; arr[curr] &lt;= target) {
    prev = curr;
    curr += step;
  }
  for (let i = prev; i &lt; Math.min(curr, n); i++) {
    if (arr[i] === target) return i;
  }
  return -1;
}

func interpolationSearch(arr []int, target int) int {
	low, high := 0, len(arr)-1
	for low &lt;= high &amp;&amp; target &gt;= arr[low] &amp;&amp; target &lt;= arr[high] {
		pos := low + (target-arr[low])*(high-low)/(arr[high]-arr[low])
		if arr[pos] == target {
			return pos
		} else if arr[pos] &lt; target {
			low = pos + 1
		} else {
			high = pos - 1
		}
	}
	return -1
}

type Stack[T any] struct {
	items []T
}

func (s *Stack[T]) Push(item T) { s.items = append(s.items, item) }

func (s *Stack[T]) Pop() (T, bool) {
	var zero T
	if len(s.items) == 0 {
		return zero, false
	}
	n := len(s.items) - 1
	item := s.items[n]
	s.items = s.items[:n]
	return item, true
}

func (s *Stack[T]) Peek() (T, bool) {
	var zero T
	if len(s.items) == 0 {
		return zero, false
	}
	return s.items[len(s.items)-1], true
}

