func (l *LinkedList) Delete(val int) {
	if l.Head == nil {
		return
	}
	if l.Head.Val == val {
		l.Head = l.Head.Next
		return
	}
	curr := l.Head
	for curr.Next != nil {
		if curr.Next.Val == val {
			curr.Next = curr.Next.Next
			return
		}
		curr = curr.Next
	}
}

