const SIZE = 256
type HashMap struct {
	buckets [SIZE][]struct{ key, val string }
}

func (h *HashMap) hash(key string) int {
	sum := 0
	for _, c := range key {
		sum += int(c)
	}
	return sum % SIZE
}

func (h *HashMap) Set(key, val string) {
	idx := h.hash(key)
	for i, kv := range h.buckets[idx] {
		if kv.key == key {
			h.buckets[idx][i].val = val
			return
		}
	}
	h.buckets[idx] = append(h.buckets[idx], struct{ key, val string }{key, val})
}

public class BSTNode {
    public int Val;
    public BSTNode? Left, Right;
    public BSTNode(int val) =&gt; Val = val;
}

public class BST {
    private BSTNode? _root;

    public void Insert(int val) =&gt; _root = Insert(_root, val);

    private BSTNode Insert(BSTNode? node, int val) {
        if (node == null) return new BSTNode(val);
        if (val &lt; node.Val) node.Left = Insert(node.Left, val);
        else if (val &gt; node.Val) node.Right = Insert(node.Right, val);
        return node;
    }

    public bool Search(int val) =&gt; Search(_root, val);

    private bool Search(BSTNode? node, int val) {
        if (node == null) return false;
        if (val == node.Val) return true;
        return val &lt; node.Val ? Search(node.Left, val) : Search(node.Right, val);
    }
}

type MinHeap struct {
	data []int
}

func (h *MinHeap) Push(val int) {
	h.data = append(h.data, val)
	i := len(h.data) - 1
	for i &gt; 0 {
		parent := (i - 1) / 2
		if h.data[parent] &lt;= h.data[i] {
			break
		}
		h.data[parent], h.data[i] = h.data[i], h.data[parent]
		i = parent
	}
}

func (h *MinHeap) Pop() int {
	min := h.data[0]
	n := len(h.data) - 1
	h.data[0] = h.data[n]
	h.data = h.data[:n]
	i := 0
	for {
		l, r, smallest := 2*i+1, 2*i+2, i
		if l &lt; n &amp;&amp; h.data[l] &lt; h.data[smallest] {
			smallest = l
		}
		if r &lt; n &amp;&amp; h.data[r] &lt; h.data[smallest] {
			smallest = r
		}
		if smallest == i {
			break
		}
		h.data[i], h.data[smallest] = h.data[smallest], h.data[i]
		i = smallest
	}
	return min
}

