func inorderIterative(root *TreeNode) []int {
	result := []int{}
	stack := []*TreeNode{}
	curr := root
	for curr != nil || len(stack) &gt; 0 {
		for curr != nil {
			stack = append(stack, curr)
			curr = curr.Left
		}
		curr = stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		result = append(result, curr.Val)
		curr = curr.Right
	}
	return result
}

function preorder(node: TreeNode | null, result: number[] = []): number[] {
  if (!node) return result;
  result.push(node.val);
  preorder(node.left, result);
  preorder(node.right, result);
  return result;
}

public List&lt;int&gt; PostorderTraversal(TreeNode root) {
    var result = new List&lt;int&gt;();
    var stack = new Stack&lt;TreeNode&gt;();
    TreeNode? prev = null;
    TreeNode? curr = root;
    while (curr != null || stack.Count &gt; 0) {
        while (curr != null) { stack.Push(curr); curr = curr.Left; }
        curr = stack.Peek();
        if (curr.Right == null || curr.Right == prev) {
            result.Add(curr.Val);
            stack.Pop();
            prev = curr;
            curr = null;
        } else {
            curr = curr.Right;
        }
    }
    return result;
}

func levelOrder(root *TreeNode) [][]int {
	result := [][]int{}
	if root == nil {
		return result
	}
	queue := []*TreeNode{root}
	for len(queue) &gt; 0 {
		level := []int{}
		size := len(queue)
		for i := 0; i &lt; size; i++ {
			node := queue[0]
			queue = queue[1:]
			level = append(level, node.Val)
			if node.Left != nil {
				queue = append(queue, node.Left)
			}
			if node.Right != nil {
				queue = append(queue, node.Right)
			}
		}
		result = append(result, level)
	}
	return result
}

func bfs(graph map[int][]int, start int) []int {
	visited := make(map[int]bool)
	queue := []int{start}
	result := []int{}
	visited[start] = true

	for len(queue) &gt; 0 {
		node := queue[0]
		queue = queue[1:]
		result = append(result, node)

		for _, neighbor := range graph[node] {
			if !visited[neighbor] {
				visited[neighbor] = true
				queue = append(queue, neighbor)
			}
		}
	}
	return result
}

func dfs(graph map[int][]int, node int, visited map[int]bool, result *[]int) {
	visited[node] = true
	*result = append(*result, node)
	for _, neighbor := range graph[node] {
		if !visited[neighbor] {
			dfs(graph, neighbor, visited, result)
		}
	}
}

public Dictionary&lt;int, int&gt; Dijkstra(Dictionary&lt;int, List&lt;(int, int)&gt;&gt; graph, int start) {
    var dist = new Dictionary&lt;int, int&gt;();
    var pq = new PriorityQueue&lt;int, int&gt;();
    foreach (var node in graph.Keys) dist[node] = int.MaxValue;
    dist[start] = 0;
    pq.Enqueue(start, 0);
    while (pq.Count &gt; 0) {
        var curr = pq.Dequeue();
        foreach (var (neighbor, weight) in graph[curr]) {
            int newDist = dist[curr] + weight;
            if (newDist &lt; dist[neighbor]) {
                dist[neighbor] = newDist;
                pq.Enqueue(neighbor, newDist);
            }
        }
    }
    return dist;
}

func bellmanFord(edges [][3]int, n, src int) ([]int, bool) {
	dist := make([]int, n)
	for i := range dist {
		dist[i] = 1&lt;&lt;31 - 1
	}
	dist[src] = 0
	for i := 0; i &lt; n-1; i++ {
		for _, e := range edges {
			u, v, w := e[0], e[1], e[2]
			if dist[u] != 1&lt;&lt;31-1 &amp;&amp; dist[u]+w &lt; dist[v] {
				dist[v] = dist[u] + w
			}
		}
	}
	for _, e := range edges {
		if dist[e[0]]+e[2] &lt; dist[e[1]] {
			return nil, true // negatif döngü var
		}
	}
	return dist, false
}

public int[,] FloydWarshall(int[,] graph, int n) {
    var dist = (int[,])graph.Clone();
    for (int k = 0; k &lt; n; k++)
        for (int i = 0; i &lt; n; i++)
            for (int j = 0; j &lt; n; j++)
                if (dist[i, k] != int.MaxValue &amp;&amp; dist[k, j] != int.MaxValue)
                    dist[i, j] = Math.Min(dist[i, j], dist[i, k] + dist[k, j]);
    return dist;
}

func topologicalSort(graph map[int][]int, n int) ([]int, bool) {
	inDegree := make([]int, n)
	for _, neighbors := range graph {
		for _, v := range neighbors {
			inDegree[v]++
		}
	}
	queue := []int{}
	for i, d := range inDegree {
		if d == 0 {
			queue = append(queue, i)
		}
	}
	result := []int{}
	for len(queue) &gt; 0 {
		node := queue[0]
		queue = queue[1:]
		result = append(result, node)
		for _, neighbor := range graph[node] {
			inDegree[neighbor]--
			if inDegree[neighbor] == 0 {
				queue = append(queue, neighbor)
			}
		}
	}
	return result, len(result) == n
}

type UnionFind struct {
	parent, rank []int
}

func NewUF(n int) *UnionFind {
	uf := &amp;UnionFind{parent: make([]int, n), rank: make([]int, n)}
	for i := range uf.parent {
		uf.parent[i] = i
	}
	return uf
}

func (uf *UnionFind) Find(x int) int {
	if uf.parent[x] != x {
		uf.parent[x] = uf.Find(uf.parent[x]) // path compression
	}
	return uf.parent[x]
}

func (uf *UnionFind) Union(x, y int) bool {
	px, py := uf.Find(x), uf.Find(y)
	if px == py {
		return false
	}
	if uf.rank[px] &lt; uf.rank[py] {
		px, py = py, px
	}
	uf.parent[py] = px
	if uf.rank[px] == uf.rank[py] {
		uf.rank[px]++
	}
	return true
}

func kruskal(n int, edges [][3]int) int {
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] &lt; edges[j][2]
	})
	uf := NewUF(n)
	totalCost := 0
	for _, e := range edges {
		if uf.Union(e[0], e[1]) {
			totalCost += e[2]
		}
	}
	return totalCost
}

func fib(n int, memo map[int]int) int {
	if n &lt;= 1 {
		return n
	}
	if v, ok := memo[n]; ok {
		return v
	}
	memo[n] = fib(n-1, memo) + fib(n-2, memo)
	return memo[n]
}

public int Knapsack(int[] weights, int[] values, int capacity) {
    int n = weights.Length;
    int[,] dp = new int[n + 1, capacity + 1];
    for (int i = 1; i &lt;= n; i++)
        for (int w = 0; w &lt;= capacity; w++) {
            dp[i, w] = dp[i - 1, w];
            if (weights[i - 1] &lt;= w)
                dp[i, w] = Math.Max(dp[i, w], dp[i - 1, w - weights[i - 1]] + values[i - 1]);
        }
    return dp[n, capacity];
}

func lcs(s1, s2 string) int {
	m, n := len(s1), len(s2)
	dp := make([][]int, m+1)
	for i := range dp {
		dp[i] = make([]int, n+1)
	}
	for i := 1; i &lt;= m; i++ {
		for j := 1; j &lt;= n; j++ {
			if s1[i-1] == s2[j-1] {
				dp[i][j] = dp[i-1][j-1] + 1
			} else {
				dp[i][j] = max(dp[i-1][j], dp[i][j-1])
			}
		}
	}
	return dp[m][n]
}

func lis(nums []int) int {
	tails := []int{}
	for _, n := range nums {
		lo, hi := 0, len(tails)
		for lo &lt; hi {
			mid := (lo + hi) / 2
			if tails[mid] &lt; n {
				lo = mid + 1
			} else {
				hi = mid
			}
		}
		if lo == len(tails) {
			tails = append(tails, n)
		} else {
			tails[lo] = n
		}
	}
	return len(tails)
}

function coinChange(coins: number[], amount: number): number {
  const dp = new Array(amount + 1).fill(Infinity);
  dp[0] = 0;
  for (let i = 1; i &lt;= amount; i++) {
    for (const coin of coins) {
      if (coin &lt;= i) {
        dp[i] = Math.min(dp[i], dp[i - coin] + 1);
      }
    }
  }
  return dp[amount] === Infinity ? -1 : dp[amount];
}

public int EditDistance(string s1, string s2) {
    int m = s1.Length, n = s2.Length;
    var dp = new int[m + 1, n + 1];
    for (int i = 0; i &lt;= m; i++) dp[i, 0] = i;
    for (int j = 0; j &lt;= n; j++) dp[0, j] = j;
    for (int i = 1; i &lt;= m; i++)
        for (int j = 1; j &lt;= n; j++)
            dp[i, j] = s1[i-1] == s2[j-1]
                ? dp[i-1, j-1]
                : 1 + Math.Min(dp[i-1, j], Math.Min(dp[i, j-1], dp[i-1, j-1]));
    return dp[m, n];
}

func activitySelection(start, end []int) int {
	n := len(start)
	order := make([]int, n)
	for i := range order {
		order[i] = i
	}
	sort.Slice(order, func(i, j int) bool {
		return end[order[i]] &lt; end[order[j]]
	})
	count := 1
	lastEnd := end[order[0]]
	for i := 1; i &lt; n; i++ {
		if start[order[i]] &gt;= lastEnd {
			count++
			lastEnd = end[order[i]]
		}
	}
	return count
}

public class HuffmanNode {
    public char? Symbol;
    public int Freq;
    public HuffmanNode? Left, Right;
}

public HuffmanNode BuildTree(Dictionary&lt;char, int&gt; freq) {
    var pq = new PriorityQueue&lt;HuffmanNode, int&gt;();
    foreach (var (ch, f) in freq)
        pq.Enqueue(new HuffmanNode { Symbol = ch, Freq = f }, f);
    while (pq.Count &gt; 1) {
        var l = pq.Dequeue();
        var r = pq.Dequeue();
        var parent = new HuffmanNode { Freq = l.Freq + r.Freq, Left = l, Right = r };
        pq.Enqueue(parent, parent.Freq);
    }
    return pq.Dequeue();
}

function fractionalKnapsack(weights: number[], values: number[], capacity: number): number {
  const items = weights.map((w, i) =&gt; ({ w, v: values[i], ratio: values[i] / w }));
  items.sort((a, b) =&gt; b.ratio - a.ratio);
  let total = 0, remaining = capacity;
  for (const item of items) {
    if (remaining &lt;= 0) break;
    const take = Math.min(item.w, remaining);
    total += take * item.ratio;
    remaining -= take;
  }
  return total;
}

func kmp(text, pattern string) []int {
	n, m := len(text), len(pattern)
	lps := buildLPS(pattern)
	result := []int{}
