		if text[i] == pattern[j] {
			i++; j++
		}
		if j == m {
			result = append(result, i-j)
			j = lps[j-1]
		} else if i &lt; n &amp;&amp; text[i] != pattern[j] {
			if j != 0 {
				j = lps[j-1]
			} else {
				i++
			}
		}
	}
	return result
}

func buildLPS(pattern string) []int {
	m := len(pattern)
	lps := make([]int, m)
	for i, len := 1, 0; i &lt; m; {
		if pattern[i] == pattern[len] {
			len++; lps[i] = len; i++
		} else if len != 0 {
			len = lps[len-1]
		} else {
			i++
		}
	}
	return lps
}

function rabinKarp(text: string, pattern: string): number[] {
  const BASE = 31, MOD = 1e9 + 9;
  const n = text.length, m = pattern.length;
  const results: number[] = [];
  let ph = 0, th = 0, power = 1;
  for (let i = 0; i &lt; m - 1; i++) power = (power * BASE) % MOD;
  for (let i = 0; i &lt; m; i++) {
    ph = (ph * BASE + pattern.charCodeAt(i)) % MOD;
    th = (th * BASE + text.charCodeAt(i)) % MOD;
  }
  for (let i = 0; i &lt;= n - m; i++) {
    if (ph === th &amp;&amp; text.slice(i, i + m) === pattern) results.push(i);
    if (i &lt; n - m) {
      th = (BASE * (th - text.charCodeAt(i) * power) + text.charCodeAt(i + m)) % MOD;
      if (th &lt; 0) th += MOD;
    }
  }
  return results;
}

func zAlgorithm(s string) []int {
	n := len(s)
	z := make([]int, n)
	l, r := 0, 0
	for i := 1; i &lt; n; i++ {
		if i &lt; r {
			z[i] = min(r-i, z[i-l])
		}
		for i+z[i] &lt; n &amp;&amp; s[z[i]] == s[i+z[i]] {
			z[i]++
		}
		if i+z[i] &gt; r {
			l, r = i, i+z[i]
		}
	}
	return z
}

func searchWithZ(text, pattern string) []int {
	s := pattern + "$" + text
	z := zAlgorithm(s)
	m := len(pattern)
	result := []int{}
	for i := m + 1; i &lt; len(s); i++ {
		if z[i] == m {
			result = append(result, i-m-1)
		}
	}
	return result
}

public int[] Manacher(string s) {
    string t = "#" + string.Join("#", s.ToCharArray()) + "#";
    int n = t.Length;
    int[] p = new int[n];
    int c = 0, r = 0;
    for (int i = 0; i &lt; n; i++) {
        int mirror = 2 * c - i;
        if (i &lt; r) p[i] = Math.Min(r - i, p[mirror]);
        while (i + p[i] + 1 &lt; n &amp;&amp; i - p[i] - 1 &gt;= 0 &amp;&amp; t[i + p[i] + 1] == t[i - p[i] - 1])
            p[i]++;
        if (i + p[i] &gt; r) { c = i; r = i + p[i]; }
    }
    return p;
}

func sieve(n int) []int {
	isPrime := make([]bool, n+1)
	for i := 2; i &lt;= n; i++ {
		isPrime[i] = true
	}
	for i := 2; i*i &lt;= n; i++ {
		if isPrime[i] {
			for j := i * i; j &lt;= n; j += i {
				isPrime[j] = false
			}
		}
	}
	primes := []int{}
	for i := 2; i &lt;= n; i++ {
		if isPrime[i] {
			primes = append(primes, i)
		}
	}
	return primes
}

public static bool MillerRabin(long n, int k = 10) {
    if (n &lt; 2) return false;
    if (n == 2 || n == 3) return true;
    if (n % 2 == 0) return false;
    long d = n - 1; int r = 0;
    while (d % 2 == 0) { d /= 2; r++; }
    var rng = new Random();
    for (int i = 0; i &lt; k; i++) {
        long a = 2 + (long)(rng.NextInt64() % (n - 3));
        long x = ModPow(a, d, n);
        if (x == 1 || x == n - 1) continue;
        bool composite = true;
        for (int j = 0; j &lt; r - 1; j++) {
            x = ModPow(x, 2, n);
            if (x == n - 1) { composite = false; break; }
        }
        if (composite) return false;
    }
    return true;
}

static long ModPow(long base, long exp, long mod) {
    long result = 1; base %= mod;
    while (exp &gt; 0) {
        if ((exp &amp; 1) == 1) result = result * base % mod;
        base = base * base % mod; exp &gt;&gt;= 1;
    }
    return result;
}

func gcd(a, b int) int {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

func lcm(a, b int) int {
	return a / gcd(a, b) * b
}

// Genişletilmiş Öklid — ax + by = gcd(a,b) çözümü
func extGcd(a, b int) (int, int, int) {
	if b == 0 {
		return a, 1, 0
	}
	g, x, y := extGcd(b, a%b)
	return g, y, x - (a/b)*y
}

func modPow(base, exp, mod int) int {
	result := 1
	base %= mod
	for exp &gt; 0 {
		if exp%2 == 1 {
			result = result * base % mod
		}
		exp /= 2
		base = base * base % mod
	}
	return result
}

function primeFactors(n: number): Map&lt;number, number&gt; {
  const factors = new Map&lt;number, number&gt;();
  for (let p = 2; p * p &lt;= n; p++) {
    while (n % p === 0) {
      factors.set(p, (factors.get(p) ?? 0) + 1);
      n = Math.floor(n / p);
    }
  }
  if (n &gt; 1) factors.set(n, (factors.get(n) ?? 0) + 1);
  return factors;
}

func eulerTotient(n int) int {
	result := n
	for p := 2; p*p &lt;= n; p++ {
		if n%p == 0 {
			for n%p == 0 {
				n /= p
			}
			result -= result / p
		}
	}
	if n &gt; 1 {
		result -= result / n
	}
	return result
}

func matMul(A, B [][]int, mod int) [][]int {
	n := len(A)
	C := make([][]int, n)
	for i := range C {
		C[i] = make([]int, n)
		for j := range C[i] {
			for k := 0; k &lt; n; k++ {
				C[i][j] = (C[i][j] + A[i][k]*B[k][j]) % mod
			}
		}
	}
	return C
}

func matPow(M [][]int, n, mod int) [][]int {
	n2 := len(M)
	result := make([][]int, n2)
	for i := range result {
		result[i] = make([]int, n2)
		result[i][i] = 1 // kimlik matrisi
	}
	for n &gt; 0 {
		if n%2 == 1 {
			result = matMul(result, M, mod)
		}
		M = matMul(M, M, mod)
		n /= 2
	}
	return result
}

function fft(a: Complex[], invert: boolean): void {
  const n = a.length;
  for (let i = 1, j = 0; i &lt; n; i++) {
    let bit = n &gt;&gt; 1;
    for (; j &amp; bit; bit &gt;&gt;= 1) j ^= bit;
    j ^= bit;
    if (i &lt; j) [a[i], a[j]] = [a[j], a[i]];
  }
  for (let len = 2; len &lt;= n; len &lt;&lt;= 1) {
    const ang = (2 * Math.PI / len) * (invert ? -1 : 1);
    const wlen = { re: Math.cos(ang), im: Math.sin(ang) };
    for (let i = 0; i &lt; n; i += len) {
      let w = { re: 1, im: 0 };
      for (let j = 0; j &lt; len / 2; j++) {
        const u = a[i + j];
        const v = cmul(w, a[i + j + len / 2]);
        a[i + j] = cadd(u, v);
        a[i + j + len / 2] = csub(u, v);
        w = cmul(w, wlen);
      }
    }
  }
  if (invert) a.forEach(x =&gt; { x.re /= n; x.im /= n; });
}

public double ClosestPair((double x, double y)[] pts) {
    Array.Sort(pts, (a, b) =&gt; a.x.CompareTo(b.x));
    return Closest(pts, 0, pts.Length - 1);
}

double Closest((double x, double y)[] pts, int l, int r) {
    if (r - l &lt;= 3) return BruteForce(pts, l, r);
    int mid = (l + r) / 2;
    double d = Math.Min(Closest(pts, l, mid), Closest(pts, mid + 1, r));
    var strip = pts[l..(r+1)].Where(p =&gt; Math.Abs(p.x - pts[mid].x) &lt; d).OrderBy(p =&gt; p.y).ToArray();
    for (int i = 0; i &lt; strip.Length; i++)
        for (int j = i + 1; j &lt; strip.Length &amp;&amp; strip[j].y - strip[i].y &lt; d; j++)
            d = Math.Min(d, Dist(strip[i], strip[j]));
    return d;
}

func solveNQueens(n int) [][]string {
	result := [][]string{}
	board := make([]int, n) // board[i] = i. satırda vezirlerin sütunu
	var bt func(row int)
	bt = func(row int) {
		if row == n {
			result = append(result, buildBoard(board, n))
			return
		}
		for col := 0; col &lt; n; col++ {
			if isValid(board, row, col) {
				board[row] = col
				bt(row + 1)
			}
		}
	}
	bt(0)
	return result
}

func isValid(board []int, row, col int) bool {
	for i := 0; i &lt; row; i++ {
		if board[i] == col || abs(board[i]-col) == abs(i-row) {
			return false
		}
	}
	return true
}

public bool SolveSudoku(char[][] board) {
    for (int i = 0; i &lt; 9; i++)
        for (int j = 0; j &lt; 9; j++) {
            if (board[i][j] != '.') continue;
            for (char c = '1'; c &lt;= '9'; c++) {
                if (IsValid(board, i, j, c)) {
                    board[i][j] = c;
                    if (SolveSudoku(board)) return true;
                    board[i][j] = '.';
                }
            }
            return false;
        }
    return true;
}

bool IsValid(char[][] b, int r, int c, char ch) {
    for (int i = 0; i &lt; 9; i++) {
        if (b[r][i] == ch || b[i][c] == ch) return false;
        if (b[3*(r/3)+i/3][3*(c/3)+i%3] == ch) return false;
    }
    return true;
}

func twoSum(arr []int, target int) (int, int) {
	l, r := 0, len(arr)-1
	for l &lt; r {
		sum := arr[l] + arr[r]
		if sum == target {
			return l, r
		} else if sum &lt; target {
			l++
		} else {
			r--
		}
	}
	return -1, -1
}

function slidingWindowMax(nums: number[], k: number): number[] {
  const result: number[] = [];
  const deque: number[] = []; // index saklar
  for (let i = 0; i &lt; nums.length; i++) {
    if (deque.length &amp;&amp; deque[0] &lt; i - k + 1) deque.shift();
    while (deque.length &amp;&amp; nums[deque[deque.length - 1]] &lt; nums[i])
      deque.pop();
    deque.push(i);
    if (i &gt;= k - 1) result.push(nums[deque[0]]);
  }
  return result;
}

func minWindow(s, t string) string {
	need := make(map[byte]int)
	for i := 0; i &lt; len(t); i++ {
		need[t[i]]++
	}
	window := make(map[byte]int)
	l, valid := 0, 0
	start, minLen := 0, math.MaxInt32
	for r := 0; r &lt; len(s); r++ {
		c := s[r]
		window[c]++
		if need[c] &gt; 0 &amp;&amp; window[c] == need[c] {
			valid++
		}
		for valid == len(need) {
			if r-l+1 &lt; minLen {
				start, minLen = l, r-l+1
			}
			if need[s[l]] &gt; 0 &amp;&amp; window[s[l]] == need[s[l]] {
				valid--
			}
			window[s[l]]--
			l++
		}
	}
	if minLen == math.MaxInt32 {
		return ""
	}
	return s[start : start+minLen]
}
